// PATCH: Cover the local changed command added outside the generator.

func TestParseChangedSinceDurationAndDate(t *testing.T) {
	now := func() time.Time { return time.Date(2026, 5, 13, 15, 30, 0, 0, time.UTC) }
	cases := []struct {
		in   string
		want time.Time
	}{
		{"8h", time.Date(2026, 5, 13, 7, 30, 0, 0, time.UTC)},
		{"7d", time.Date(2026, 5, 6, 15, 30, 0, 0, time.UTC)},
		{"2w", time.Date(2026, 4, 29, 15, 30, 0, 0, time.UTC)},
		{"3", time.Date(2026, 5, 10, 15, 30, 0, 0, time.UTC)},
		{"2026-05-01", time.Date(2026, 5, 1, 0, 0, 0, 0, time.UTC)},
	}

	for _, tc := range cases {
		got, err := parseChangedSince(tc.in, now)
		if err != nil {
			t.Fatalf("parseChangedSince(%q): %v", tc.in, err)
		}
		if !got.Equal(tc.want) {
			t.Errorf("parseChangedSince(%q) = %s, want %s", tc.in, got, tc.want)
		}
	}
}

func TestParseChangedSinceRejectsInvalid(t *testing.T) {
	if _, err := parseChangedSince("yesterday", time.Now); err == nil {
		t.Fatal("parseChangedSince(yesterday) expected error")
	}
}

func TestChangedItemFromObject(t *testing.T) {
	cutoff := time.Date(2026, 5, 1, 0, 0, 0, 0, time.UTC)
	amount := 12.34
	item, ok := changedItemFromObject("transactions", map[string]any{
		"id":         float64(123),
		"payee":      "Coffee Shop",
		"amount":     "12.34",
		"created_at": "2026-05-02T10:00:00Z",
		"updated_at": "2026-05-03T10:00:00Z",
	}, cutoff)
	if !ok {
		t.Fatal("changedItemFromObject returned false")
	}
	if item.ResourceType != "transactions" || item.ID != "123" || item.NameOrPayee != "Coffee Shop" {
		t.Fatalf("unexpected item identity: %+v", item)
	}
	if item.Amount == nil || math.Abs(*item.Amount-amount) > 0.000001 {
		t.Fatalf("amount = %v, want %.2f", item.Amount, amount)
	}
	if item.ChangeType != "updated" {
		t.Fatalf("change type = %q, want updated", item.ChangeType)
	}
}

func TestChangedItemFromObjectBudgetFallback(t *testing.T) {
	cutoff := time.Date(2026, 5, 1, 0, 0, 0, 0, time.UTC)
	item, ok := changedItemFromObject("budgets", map[string]any{
		"category_id": float64(42),
		"updated_at":  "2026-05-03T10:00:00Z",
	}, cutoff)
	if !ok {
		t.Fatal("changedItemFromObject returned false")
	}
	if item.NameOrPayee != "42" || item.ChangeType != "created" {
		t.Fatalf("budget fallback item = %+v", item)
	}
}

func TestQueryChangedTransactionsFindsSpaceSeparatedUpdatedAt(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	db, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	defer db.Close()

	items := []json.RawMessage{
		json.RawMessage(`{"id":"old","payee":"Old Charge","amount":"10.00","created_at":"2026-05-13 09:00:00","updated_at":"2026-05-13 09:00:00"}`),
		json.RawMessage(`{"id":"recent","payee":"Recent Charge","amount":"20.00","created_at":"2026-05-13 10:00:00","updated_at":"2026-05-13 10:00:00"}`),
	}
	if _, _, err := db.UpsertBatch("transactions", items); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	cutoff := time.Date(2026, 5, 13, 9, 30, 0, 0, time.UTC)
	changed, err := queryChangedTransactions(context.Background(), db.DB(), cutoff, 0)
	if err != nil {
		t.Fatalf("queryChangedTransactions: %v", err)
	}
	if len(changed) != 1 {
		t.Fatalf("changed = %+v, want one recent transaction", changed)
	}
	if changed[0].ID != "recent" {
		t.Fatalf("changed[0].ID = %q, want recent", changed[0].ID)
	}
}

func TestChangedCommandWritesToCommandOutput(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	db, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	defer db.Close()

	if _, _, err := db.UpsertBatch("transactions", []json.RawMessage{
		json.RawMessage(`{"id":"recent","payee":"Recent Charge","amount":"20.00","created_at":"2026-05-13T10:00:00Z","updated_at":"2026-05-13T10:00:00Z"}`),
	}); err != nil {
		t.Fatalf("UpsertBatch: %v", err)
	}

	flags := &rootFlags{asJSON: true}
	cmd := newChangedCmd(flags)
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetContext(context.Background())
	if err := cmd.Flags().Set("since", "2026-05-01"); err != nil {
		t.Fatalf("set since: %v", err)
	}
	if err := cmd.Flags().Set("types", "transactions"); err != nil {
		t.Fatalf("set types: %v", err)
	}
	if err := cmd.Flags().Set("db", dbPath); err != nil {
		t.Fatalf("set db: %v", err)
	}

	if err := cmd.RunE(cmd, nil); err != nil {
		t.Fatalf("RunE: %v", err)
	}
	if !strings.Contains(out.String(), `"id":"recent"`) {
		t.Fatalf("command output = %q, want JSON result in command output writer", out.String())
	}
}

